87	pub fn jaccard(a: &[u64], b: &[u64]) -> f64 {
88	    if a.is_empty() && b.is_empty() {
89	        return 1.0;
90	    }
91	    let set_a: HashSet<u64> = a.iter().copied().collect();
92	    let set_b: HashSet<u64> = b.iter().copied().collect();
93	    let intersection = set_a.intersection(&set_b).count();
94	    let union = set_a.union(&set_b).count();
95	    if union == 0 {
96	        return 0.0;
97	    }
98	    intersection as f64 / union as f64
99	}
