105	pub fn make_pair(a: &FunctionInfo, b: &FunctionInfo, score: f64) -> DuplicatePair {
106	    let (left, right) = order_endpoints(a, b);
107	    DuplicatePair {
108	        score,
109	        left: PairEndpoint {
110	            file: left.file.clone(),
111	            start_line: left.start_line,
112	            end_line: left.end_line,
113	            nodes: left.node_hashes.len(),
114	        },
115	        right: PairEndpoint {
116	            file: right.file.clone(),
117	            start_line: right.start_line,
118	            end_line: right.end_line,
119	            nodes: right.node_hashes.len(),
120	        },
121	    }
122	}
