128	pub fn find_duplicate_pairs(
129	    functions: &[FunctionInfo],
130	    threshold: f64,
131	    min_lines: usize,
132	    min_nodes: usize,
133	) -> Vec<DuplicatePair> {
134	    let candidates: Vec<&FunctionInfo> = functions
135	        .iter()
136	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
137	        .collect();
138	
139	    let mut pairs: Vec<DuplicatePair> = Vec::new();
140	
141	    for i in 0..candidates.len() {
142	        for j in (i + 1)..candidates.len() {
143	            let a = candidates[i];
144	            let b = candidates[j];
145	            if is_same_location(a, b) {
146	                continue;
147	            }
148	            let score = jaccard(&a.node_hashes, &b.node_hashes);
149	            if score >= threshold {
150	                pairs.push(make_pair(a, b, score));
151	            }
152	        }
153	    }
154	
155	    pairs.sort_by(|a, b| {
156	        b.score
157	            .partial_cmp(&a.score)
158	            .unwrap_or(std::cmp::Ordering::Equal)
159	            .then_with(|| a.left.file.cmp(&b.left.file))
160	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
161	            .then_with(|| a.right.file.cmp(&b.right.file))
162	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
163	    });
164	
165	    pairs
166	}
