168	fn order_endpoints<'a>(
169	    a: &'a FunctionInfo,
170	    b: &'a FunctionInfo,
171	) -> (&'a FunctionInfo, &'a FunctionInfo) {
172	    let cmp = a
173	        .file
174	        .cmp(&b.file)
175	        .then_with(|| a.start_line.cmp(&b.start_line));
176	    if cmp == std::cmp::Ordering::Greater {
177	        (b, a)
178	    } else {
179	        (a, b)
180	    }
181	}
