248	pub fn execute_cli(
249	    paths: &[String],
250	    format_str: &str,
251	    lang: Option<&str>,
252	    config: Config,
253	    run_fn: impl Fn(&[String], &Config) -> RunResult,
254	) -> CliResult {
255	    let format = match parse_output_format(format_str) {
256	        Ok(f) => f,
257	        Err(e) => return cli_error(e),
258	    };
259	
260	    let lang_val = if let Some(lang) = lang {
261	        match validate_lang(lang) {
262	            Ok(l) => Some(l),
263	            Err(e) => return cli_error(e),
264	        }
265	    } else {
266	        None
267	    };
268	
269	    let config = Config {
270	        format,
271	        lang: lang_val,
272	        ..config
273	    };
274	    let result = run_fn(paths, &config);
275	    run_result_to_cli(result, &config.format)
276	}
