1	//! This crate provides TypeScript and TSX language support for the [tree-sitter][] parsing library.
2	//!
3	//! Typically, you will use the [LANGUAGE_TYPESCRIPT] constant to add this language to a
4	//! tree-sitter [Parser][], and then use the parser to parse some code:
5	//!
6	//! ```
7	//! use tree_sitter::Parser;
8	//!
9	//! let code = r#"
10	//! function double(x: number): number {
11	//!     return x * 2;
12	//! }
13	//! "#;
14	//! let mut parser = Parser::new();
15	//! let language = tree_sitter_typescript::LANGUAGE_TYPESCRIPT;
16	//! parser
17	//!     .set_language(&language.into())
18	//!     .expect("Error loading TypeScript parser");
19	//! let tree = parser.parse(code, None).unwrap();
20	//! assert!(!tree.root_node().has_error());
21	//! ```
